import boto3

def create_sns_subscription(topic_arn, protocol, endpoint):
    sns = boto3.client('sns')
    response = sns.subscribe(TopicArn=topic_arn, Protocol=protocol, Endpoint=endpoint)
    
    return response['SubscriptionArn']

# Accept subscription endpoints from user input
user_provided_url = input("Enter the endpoint URL: ")
topic_arn = input("Enter the topic ARN: ")

response_arn = create_sns_subscription(topic_arn, 'https', user_provided_url)
print(f"Subscribed with ARN: {response_arn}")